import { By } from 'selenium-webdriver';
import { DriverLike, register } from '@oracle/oraclejet-webdriver';
import { AccordionItemSingleWebElement } from './AccordionItemSingleWebElement';
export { AccordionItemSingleWebElement };

/**
 * Retrieve an instance of [AccordionItemSingleWebElement](../classes/AccordionItemSingleWebElement.html).
 * @example
 * ```javascript
 * import { findAccordionItemSingle } from '@oracle/oraclejet-core-pack/webdriver';
 * const el = await findAccordionItemSingle(driver, By.id('my-oj-c-accordion-item-single'));
 * ```
 * @param driver A WebDriver/WebElement instance from where the element will be
 * searched. If WebDriver is passed, the element will be searched globally in the
 * document. If WebElement is passed, the search will be relative to this element.
 * @param by The locator with which to find the element
 */
export async function findAccordionItemSingle(
  driver: DriverLike,
  by: By
): Promise<AccordionItemSingleWebElement> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type AccordionItemSingleWebElement
  if (!(webEl instanceof AccordionItemSingleWebElement)) {
    const tagName = await webEl.getTagName();
    let supplemental = '';
    if (webEl.constructor.name === 'AccordionItemSingleWebElement') {
      supplemental = 'You likely have multiple installations of this package.';
    }
    throw Error(
      `findAccordionItemSingle(${by}) created ${webEl.constructor.name} for <${tagName}>, but expected ${AccordionItemSingleWebElement.name}. ${supplemental}`
    );
  }
  return webEl;
}

register('oj-c-accordion-item-single', AccordionItemSingleWebElement);
